import { render, screen, fireEvent } from '@testing-library/react';
import '@testing-library/jest-dom';
import React from 'react';
import App from './App';

describe('Accessible Data Table', () => {
  it('renders a semantic table with caption', () => {
    render(<App />);
    const table = screen.getByTestId('data-table');
    expect(table.tagName).toBe('TABLE');
    const caption = table.querySelector('caption');
    expect(caption).toBeInTheDocument();
  });

  it('sortable headers have aria-sort', () => {
    render(<App />);
    const nameSort = screen.getByTestId('sort-name');
    expect(nameSort.closest('th')).toHaveAttribute('aria-sort');
  });

  it('clicking sort changes aria-sort', () => {
    render(<App />);
    const th = screen.getByTestId('sort-name').closest('th')!;
    expect(th).toHaveAttribute('aria-sort', 'none');
    fireEvent.click(screen.getByTestId('sort-name'));
    expect(th).toHaveAttribute('aria-sort', 'ascending');
    fireEvent.click(screen.getByTestId('sort-name'));
    expect(th).toHaveAttribute('aria-sort', 'descending');
  });

  it('sort announcement updates', () => {
    render(<App />);
    fireEvent.click(screen.getByTestId('sort-name'));
    const ann = screen.getByTestId('sort-announcement');
    expect(ann.textContent).toBeTruthy();
  });

  it('select all checkbox works', () => {
    render(<App />);
    fireEvent.click(screen.getByTestId('select-all'));
    expect(screen.getByTestId('selected-count')).toHaveTextContent('5');
    fireEvent.click(screen.getByTestId('select-all'));
    expect(screen.getByTestId('selected-count')).toHaveTextContent('0');
  });

  it('individual row selection works', () => {
    render(<App />);
    fireEvent.click(screen.getByTestId('select-row-1'));
    expect(screen.getByTestId('selected-count')).toHaveTextContent('1');
    fireEvent.click(screen.getByTestId('select-row-1'));
    expect(screen.getByTestId('selected-count')).toHaveTextContent('0');
  });

  it('row checkboxes have aria-label', () => {
    render(<App />);
    const cb = screen.getByTestId('select-row-1');
    expect(cb).toHaveAttribute('aria-label');
  });

  it('sort announcement region has aria-live', () => {
    render(<App />);
    expect(screen.getByTestId('sort-announcement')).toHaveAttribute('aria-live', 'polite');
  });
});

