import React, { useState, useRef, useEffect, useCallback } from 'react';
import './styles.css';

interface Column {
  key: string;
  label: string;
  sortable?: boolean;
}

interface Row {
  id: number;
  [key: string]: any;
}

type SortDir = 'ascending' | 'descending' | 'none';

interface DataTableProps {
  data: Row[];
  columns: Column[];
  caption: string;
}

export const DataTable: React.FC<DataTableProps> = ({ data, columns, caption }) => {
  const [sortKey, setSortKey] = useState<string | null>(null);
  const [sortDir, setSortDir] = useState<SortDir>('none');
  const [selected, setSelected] = useState<Set<number>>(new Set());
  const [announcement, setAnnouncement] = useState('');
  const selectAllRef = useRef<HTMLInputElement>(null);

  const handleSort = (key: string) => {
    let nextDir: SortDir;
    if (sortKey !== key) {
      nextDir = 'ascending';
    } else {
      const cycle: SortDir[] = ['ascending', 'descending', 'none'];
      const idx = cycle.indexOf(sortDir);
      nextDir = cycle[(idx + 1) % 3];
    }
    setSortKey(nextDir === 'none' ? null : key);
    setSortDir(nextDir);
    const col = columns.find(c => c.key === key);
    if (nextDir === 'none') {
      setAnnouncement(`${col?.label} sort removed`);
    } else {
      setAnnouncement(`${col?.label} sorted ${nextDir}`);
    }
  };

  const toggleRow = (id: number) => {
    setSelected(prev => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      return next;
    });
  };

  const toggleAll = () => {
    if (selected.size === data.length) {
      setSelected(new Set());
    } else {
      setSelected(new Set(data.map(r => r.id)));
    }
  };

  // Indeterminate state
  useEffect(() => {
    if (selectAllRef.current) {
      selectAllRef.current.indeterminate = selected.size > 0 && selected.size < data.length;
    }
  }, [selected, data.length]);

  const sortedData = [...data];
  if (sortKey && sortDir !== 'none') {
    sortedData.sort((a, b) => {
      const aVal = String(a[sortKey]);
      const bVal = String(b[sortKey]);
      const cmp = aVal.localeCompare(bVal);
      return sortDir === 'ascending' ? cmp : -cmp;
    });
  }

  const getSortDir = (key: string): SortDir => {
    return sortKey === key ? sortDir : 'none';
  };

  return (
    <div>
      <p data-testid="selected-count" className="table-selected">
        {selected.size} selected
      </p>

      <div data-testid="sort-announcement" aria-live="polite" className="sr-only">
        {announcement}
      </div>

      <div className="table-region" role="region" aria-label={caption} tabIndex={0}>
        <table data-testid="data-table" className="data-table">
          <caption>{caption}</caption>
          <thead>
            <tr>
              <th scope="col">
                <input
                  ref={selectAllRef}
                  data-testid="select-all"
                  type="checkbox"
                  checked={selected.size === data.length}
                  onChange={toggleAll}
                  aria-label="Select all rows"
                />
              </th>
              {columns.map(col => (
                <th key={col.key} scope="col" aria-sort={col.sortable ? getSortDir(col.key) : undefined}>
                  {col.sortable ? (
                    <button
                      data-testid={`sort-${col.key}`}
                      className="sort-btn"
                      onClick={() => handleSort(col.key)}
                    >
                      {col.label}
                      <span className={`sort-icon${getSortDir(col.key) !== 'none' ? ' sort-icon--active' : ''}`}>
                        {getSortDir(col.key) === 'ascending' ? '▲' : getSortDir(col.key) === 'descending' ? '▼' : '⇅'}
                      </span>
                    </button>
                  ) : col.label}
                </th>
              ))}
            </tr>
          </thead>
          <tbody>
            {sortedData.map(row => (
              <tr key={row.id} className={selected.has(row.id) ? 'row--selected' : ''}>
                <td>
                  <input
                    data-testid={`select-row-${row.id}`}
                    type="checkbox"
                    checked={selected.has(row.id)}
                    onChange={() => toggleRow(row.id)}
                    aria-label={`Select ${row.name}`}
                  />
                </td>
                {columns.map(col => (
                  <td key={col.key}>{row[col.key]}</td>
                ))}
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};
